function hc_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function hc_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function hc_c($v){return strtoupper(trim((string)$v));}
function hc_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
function hc_date_ok($v){return (bool)preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)$v);}
