function hc_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function hc_day_name($date){$n=array('Minggu','Senin','Selasa','Rabu','Kamis','Jumat','Sabtu');return $n[(int)date('w',strtotime($date))];}
function hc_weekday_no($date){return (int)date('w',strtotime($date))+1;}
function hc_row($id){global $db;return $db->fetch("SELECT hc.*,fc.calendar_name,wl.location_code,wl.location_name FROM erp_holiday_calendar hc LEFT JOIN erp_factory_calendar_header fc ON fc.id=hc.calendar_id LEFT JOIN erp_work_location wl ON wl.id=hc.work_location_id WHERE hc.id=? LIMIT 1",array((int)$id));}
function hc_payload($r){$d=(array)$r;$d['calendar_text']=$r->calendar_id?($r->calendar_code.' - '.$r->calendar_name.' ['.$r->plant_code.']'):'';$d['work_location_text']=$r->work_location_id?($r->location_code.' - '.$r->location_name):'';return $d;}
function hc_apply($h){
  global $db,$username;
  if(!$h->calendar_id)return 0;
  $start=strtotime($h->holiday_date);$end=strtotime($h->holiday_end_date?:$h->holiday_date);$count=0;
  for($t=$start;$t<=$end;$t=strtotime('+1 day',$t)){
    $date=date('Y-m-d',$t);$tipe=((float)$h->working_hours)>0?'Khusus':'Libur';$ket=$h->holiday_code.' - '.$h->holiday_name;
    $exist=$db->fetch("SELECT id FROM erp_factory_calendar WHERE calendar_id=? AND tanggal=? LIMIT 1",array($h->calendar_id,$date));
    $data=array('calendar_code'=>$h->calendar_code,'plant_code'=>$h->plant_code,'tanggal'=>$date,'nama_hari'=>hc_day_name($date),'weekday_no'=>hc_weekday_no($date),'tipe_hari'=>$tipe,'shift_id'=>null,'shift_code'=>null,'working_hours'=>(float)$h->working_hours,'exception_type'=>$h->holiday_type,'source_type'=>'HOLIDAY_CALENDAR','keterangan'=>$ket,'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s'));
    if($exist)$db->update('erp_factory_calendar',$data,'id',$exist->id);
    else{$data['calendar_id']=$h->calendar_id;$db->insert('erp_factory_calendar',$data);}
    $count++;
  }
  return $count;
}
function hc_rows($from,$to,$type,$scope,$status,$calendar,$kw){global $db;$w=" WHERE hc.holiday_date<=? AND COALESCE(hc.holiday_end_date,hc.holiday_date)>=? ";$p=array($to,$from);if($type!==''){$w.=" AND hc.holiday_type=? ";$p[]=$type;}if($scope!==''){$w.=" AND hc.holiday_scope=? ";$p[]=$scope;}if($status!==''){$w.=" AND hc.holiday_status=? ";$p[]=$status;}if($calendar!==''){$w.=" AND hc.calendar_id=? ";$p[]=(int)$calendar;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (hc.holiday_code LIKE ? OR hc.holiday_name LIKE ? OR hc.region_code LIKE ? OR hc.source_reference LIKE ? OR hc.sap_reference LIKE ?) ";array_push($p,$like,$like,$like,$like,$like);}return $db->query("SELECT hc.*,fc.calendar_name,wl.location_code,wl.location_name FROM erp_holiday_calendar hc LEFT JOIN erp_factory_calendar_header fc ON fc.id=hc.calendar_id LEFT JOIN erp_work_location wl ON wl.id=hc.work_location_id $w ORDER BY hc.holiday_date,hc.holiday_code",$p);}
