  if($code===''||!preg_match('/^[A-Z0-9_-]{3,30}$/',$code))hc_json('error','Holiday Code wajib diisi dan hanya boleh huruf besar/angka/underscore/dash.');if($name==='')hc_json('error','Holiday Name wajib diisi.');if(!hc_date_ok($from))hc_json('error','Holiday Date wajib format YYYY-MM-DD.');if($to==='' )$to=$from;if(!hc_date_ok($to)||strtotime($to)<strtotime($from))hc_json('error','Holiday End Date tidak valid.');if(!in_array($type,$types,true)||!in_array($scope,$scopes,true)||!in_array($status,$stats,true))hc_json('error','Type/scope/status tidak valid.');
  $calId=hc_p('calendar_id')!==''?(int)hc_p('calendar_id'):null;$calCode=null;$plantCode=null;if($calId){$cal=$db->fetch("SELECT * FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($calId));if(!$cal)hc_json('error','Factory Calendar tidak valid.');$calCode=$cal->calendar_code;$plantCode=$cal->plant_code;}
  $locId=hc_p('work_location_id')!==''?(int)hc_p('work_location_id'):null;if($locId&&!$db->fetch("SELECT id FROM erp_work_location WHERE id=? LIMIT 1",array($locId)))hc_json('error','Work Location tidak valid.');
