  $paid=hc_c(hc_p('paid_holiday','Y'));$rec=hc_c(hc_p('recurring_annual','N'));if(!in_array($paid,$yn,true)||!in_array($rec,$yn,true))hc_json('error','Paid/Recurring flag tidak valid.');
